// ---- Test 3: ec_recover_y ----
#[test]
fn test_ec_recover_y() {
    let e0 = EcCurve::<Level1>::default();

    // (3+i) on E0 (A=0)
    let px = fp2_small::<Level1>(3, 1);
    let (y, ret) = ec_recover_y(&px, &e0);
    // C returns 0 for (3+i), not on curve
    assert!(!bool::from(ret));
    let y_bytes = fp2_encode_arr(&y);
    assert_fp2(
        "y(3+i)",
        &y_bytes,
        &hex!("1a525a47e979b9087de8c6bfca64b97b2ec2f418078ade99d674c65ef504da007051b5eaf2283c002a87ff577479368285a1745138f544a5b3dfc3479734a803"),
    );

    // (7+2i) on E1 (A=6)
    let e1 = EcCurve::<Level1> {
        a: fp2_small(6, 0),
        c: Fp2::one(),
        ..EcCurve::default()
    };
    let px = fp2_small::<Level1>(7, 2);
    let (y, ret) = ec_recover_y(&px, &e1);
    assert!(!bool::from(ret));
    let y_bytes = fp2_encode_arr(&y);
    assert_fp2(
        "y_E1(7+2i)",
        &y_bytes,
        &hex!("344eccf7c763046e29837198360e47bbe48f9ac806db85fda261573da3075401d390383bb497b742874e6a0057520233ef41535a96bb4890a04554d57f7a4800"),
    );
}

