#[test]
fn test_basis_generation_e1_with_hints() {
    let mut curve = EcCurve::<Level1> {
        a: fp2_small(6, 0),
        c: Fp2::one(),
        ..EcCurve::default()
    };
    curve.normalize_a24();

    let (basis, hint) = ec_curve_to_basis_2f_to_hint(
        &mut curve,
        TORSION_EVEN_POWER,
        &BASIS_E0_PX_BYTES,
        &BASIS_E0_QX_BYTES,
        P_COFACTOR_FOR_2F,
        P_COFACTOR_FOR_2F_BITLENGTH as usize,
        TORSION_EVEN_POWER,
    )
    .unwrap();

    assert!(inner_test_generated_basis(
        &basis,
        &curve,
        TORSION_EVEN_POWER
    ));

    // Generate from hint, should produce identical basis
    let mut curve2 = EcCurve::<Level1> {
        a: fp2_small(6, 0),
        c: Fp2::one(),
        ..EcCurve::default()
    };
    curve2.normalize_a24();

    let (basis_hint, ok) = ec_curve_to_basis_2f_from_hint(
        &mut curve2,
        TORSION_EVEN_POWER,
        hint,
        &BASIS_E0_PX_BYTES,
        &BASIS_E0_QX_BYTES,
        P_COFACTOR_FOR_2F,
        P_COFACTOR_FOR_2F_BITLENGTH as usize,
        TORSION_EVEN_POWER,
    )
    .unwrap();
    assert_eq!(ok, 1);

    assert!(
        bool::from(basis.p.ct_equal(&basis_hint.p)),
        "P should match"
    );
    assert!(
        bool::from(basis.q.ct_equal(&basis_hint.q)),
        "Q should match"
    );
    assert!(
        bool::from(basis.pmq.ct_equal(&basis_hint.pmq)),
        "PmQ should match"
    );
}
